#include "XSbench_header.cuh"

__global__ void xs_lookup_kernel_baseline(Inputs in, SimulationData GSD)
{
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i >= in.lookups)
        return;

    uint64_t seed = STARTING_SEED;
    seed = fast_forward_LCG(seed, 2 * i);

    double p_energy = LCG_random_double(&seed);
    int mat = pick_mat(&seed);

    double macro_xs_vector[5] = {0};

    calculate_macro_xs(
        p_energy,
        mat,
        in.n_isotopes,
        in.n_gridpoints,
        GSD.num_nucs,
        GSD.concs,
        GSD.unionized_energy_array,
        GSD.index_grid,
        GSD.nuclide_grid,
        GSD.mats,
        macro_xs_vector,
        in.grid_type,
        in.hash_bins,
        GSD.max_num_nucs);

    double max_val = -1.0;
    int max_idx = 0;
    for (int j = 0; j < 5; j++)
    {
        if (macro_xs_vector[j] > max_val)
        {
            max_val = macro_xs_vector[j];
            max_idx = j;
        }
    }
    atomicAdd(GSD.verification, max_idx + 1);
}

unsigned long long run_event_based_simulation_baseline(Inputs in, SimulationData GSD, int mype)
{
    if (mype == 0)
        printf("Beginning event based simulation...\n");

    int threads_per_block = 256;
    int blocks = (in.lookups + threads_per_block - 1) / threads_per_block;

    cudaMemset(GSD.verification, 0, sizeof(unsigned long));
    xs_lookup_kernel_baseline<<<blocks, threads_per_block>>>(in, GSD);
    gpuErrchk(cudaDeviceSynchronize());

    unsigned long long verification_host;
    gpuErrchk(cudaMemcpy(&verification_host, GSD.verification, sizeof(unsigned long), cudaMemcpyDeviceToHost));

    return verification_host;
}

__global__ void sampling_kernel(Inputs in, SimulationData GSD)
{
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i >= in.lookups)
