unsigned long long run_event_based_simulation_optimization_1(Inputs in, SimulationData GSD, int mype)
{
    char *optimization_name = (char *)"Optimization 1 - Kernel splitting + full material & energy sort";

    if (mype == 0)
        printf("Simulation Kernel:\"%s\"\n", optimization_name);

    if (mype == 0)
        printf("Allocating additional data required by optimized kernel...\n");
    size_t sz;
    size_t total_sz = 0;
    double start, stop;

    int i = 0;
    int m = 0;

    sz = in.lookups * sizeof(double);
    cudaMallocHost(&GSD.p_energy_samples, sz);
    total_sz += sz;
    GSD.length_p_energy_samples = in.lookups;

    sz = in.lookups * sizeof(int);
    cudaMallocHost(&GSD.mat_samples, sz);
    total_sz += sz;
    GSD.length_mat_samples = in.lookups;

    if (mype == 0)
        printf("Allocated an additional %.0lf MB of data on host pinned memory.\n", total_sz / 1024.0 / 1024.0);

    // Sampling on CPU (could be done on GPU but to keep same pattern)
    #pragma omp parallel for schedule(dynamic, 100)
    for (i = 0; i < in.lookups; i++)
    {
        uint64_t seed = STARTING_SEED;
        seed = fast_forward_LCG(seed, 2 * i);

        double p_energy = LCG_random_double(&seed);
        int mat = pick_mat(&seed);

        GSD.p_energy_samples[i] = p_energy;
        GSD.mat_samples[i] = mat;
    }
    if (mype == 0)
        printf("finished sampling...\n");

    start = get_time();

    // Sort by material on CPU
    quickSort_parallel_i_d(GSD.mat_samples, GSD.p_energy_samples, in.lookups, in.nthreads);

    stop = get_time();

    if (mype == 0)
        printf("Material sort took %.3lf seconds\n", stop - start);

    start = get_time();

    int num_samples_per_mat[12] = {0};
    for (int l = 0; l < in.lookups; l++)
        num_samples_per_mat[GSD.mat_samples[l]]++;

    int offsets[12] = {0};
    for (int m = 1; m < 12; m++)
        offsets[m] = offsets[m - 1] + num_samples_per_mat[m - 1];

    stop = get_time();
    if (mype == 0)
        printf("Counting samples and offsets took %.3lf seconds\n", stop - start);
    start = stop;

    for (int m = 0; m < 12; m++)
        quickSort_parallel_d_i(GSD.p_energy_samples + offsets[m], GSD.mat_samples + offsets[m], num_samples_per_mat[m], in.nthreads);

    stop = get_time();
    if (mype == 0)
        printf("Energy Sorts took %.3lf seconds\n", stop - start);

    // Move p_energy_samples and mat_samples to device
    double *d_p_energy_samples;
    int *d_mat_samples;
    cudaMalloc(&d_p_energy_samples, in.lookups * sizeof(double));
    cudaMalloc(&d_mat_samples, in.lookups * sizeof(int));
    cudaMemcpy(d_p_energy_samples, GSD.p_energy_samples, in.lookups * sizeof(double), cudaMemcpyHostToDevice);
    cudaMemcpy(d_mat_samples, GSD.mat_samples, in.lookups * sizeof(int), cudaMemcpyHostToDevice);

    GSD.p_energy_samples = d_p_energy_samples;
    GSD.mat_samples = d_mat_samples;

    // Allocate and zero verification on device
    unsigned long *d_verification;
    cudaMalloc(&d_verification, sizeof(unsigned long));
    cudaMemset(d_verification, 0, sizeof(unsigned long));
    GSD.verification = d_verification;

    start = get_time();

    unsigned long long verification = 0;

    for (m = 0; m < 12; m++)
    {
        int offset = offsets[m];
        int n_lookups = num_samples_per_mat[m];
        if (n_lookups == 0)
            continue;
        int threads_per_block = 256;
        int blocks = (n_lookups + threads_per_block - 1) / threads_per_block;

        xs_lookup_kernel_optimization_1<<<blocks, threads_per_block>>>(in, GSD, offset, n_lookups);
        gpuErrchk(cudaDeviceSynchronize());
    }

    gpuErrchk(cudaMemcpy(&verification, GSD.verification, sizeof(unsigned long), cudaMemcpyDeviceToHost));

    stop = get_time();
    if (mype == 0)
        printf("XS Lookups took %.3lf seconds\n", stop - start);

    cudaFree(d_p_energy_samples);
    cudaFree(d_mat_samples);
    cudaFree(d_verification);
    cudaFreeHost(GSD.p_energy_samples);
    cudaFreeHost(GSD.mat_samples);
    GSD.p_energy_samples = NULL;
    GSD.mat_samples = NULL;
    GSD.verification = NULL;

    return verification;
}

